            in_edges.add(new ArrayList<>());
        }

        for (long[] edge : edges) {
            long u = edge[0];
            long v = edge[1];
            long w = edge[2];
            out_edges.get((int)u).add(new long[] { (int)v, (int)w });
            in_edges.get((int)v).add(new long[] { (int)u, (int)w });
        }

        long INF = Long.MAX_VALUE;
        long[][] dist = new long[size][2];
        for (int i = 0; i < size; i++) {
            dist[i][0] = INF;
            dist[i][1] = INF;
