                        pq.offer(new long[] { new_cost, v, 0 });
                    }
                }

                for (long[] in : in_edges.get((int)u)) {
                    long v = in[0];
                    long w = in[1];
                    long new_cost = current_cost + 2 * w;
                    if (new_cost < dist[v][1]) {
                        dist[v][1] = new_cost;
                        pq.offer(new long[] { new_cost, v, 1 });
