                    if (new_cost < dist[v][1]) {
                        dist[v][1] = new_cost;
                        pq.offer(new long[] { new_cost, v, 1 });
                    }
                }
            }
        }

        long min = Math.min(dist[size - 1][0], dist[size - 1][1]);
        return min == INF ? -1 : min;
    }
